import os
import requests
from functools import wraps
from flask import Flask, request, jsonify, g
import jwt
from datetime import datetime, timedelta

app = Flask(__name__)

# Configuration - use environment variables, never hardcode secrets
app.config['JWT_SECRET_KEY'] = os.environ.get('JWT_SECRET_KEY')
app.config['JWT_ALGORITHM'] = os.environ.get('JWT_ALGORITHM', 'HS256')
app.config['JWT_ISSUER'] = os.environ.get('JWT_ISSUER', 'your-auth-service')
app.config['BACKEND_SERVICE_URL'] = os.environ.get('BACKEND_SERVICE_URL', 'http://localhost:5001')

# For RS256 with JWKS (more production-appropriate)
app.config['JWKS_URL'] = os.environ.get('JWKS_URL', '')

_jwks_cache = None
_jwks_cache_time = None
JWKS_CACHE_TTL = 300  # seconds


def get_jwks_public_key(token_header):
    """Fetch and cache JWKS public keys for RS256 verification."""
    global _jwks_cache, _jwks_cache_time

    if not app.config['JWKS_URL']:
        return None

    now = datetime.utcnow()
    if _jwks_cache is None or _jwks_cache_time is None or \
       (now - _jwks_cache_time).total_seconds() > JWKS_CACHE_TTL:
        try:
            resp = requests.get(app.config['JWKS_URL'], timeout=5)
            resp.raise_for_status()
            _jwks_cache = resp.json()
            _jwks_cache_time = now
        except requests.RequestException as e:
            app.logger.error(f"Failed to fetch JWKS: {e}")
            if _jwks_cache is not None:
                return _jwks_cache  # use stale cache as fallback
            raise

    kid = token_header.get('kid')
    if kid and 'keys' in _jwks_cache:
        for key_data in _jwks_cache['keys']:
            if key_data.get('kid') == kid:
                return jwt.algorithms.RSAAlgorithm.from_jwk(key_data)

    raise ValueError(f"No matching key found for kid: {kid}")


def decode_and_verify_token(token):
    """
    Decode and VERIFY a JWT token. Never skip verification.
    Supports both HS256 (shared secret) and RS256 (JWKS).
    """
    if not token:
        raise ValueError("No token provided")

    # Peek at header to determine algorithm (without trusting it blindly)
    try:
        unverified_header = jwt.get_unverified_header(token)
    except jwt.DecodeError as e:
        raise ValueError(f"Invalid token format: {e}")

    algorithm = unverified_header.get('alg', '')

    # Only allow expected algorithms - prevents algorithm confusion attacks
    allowed_algorithms = [app.config['JWT_ALGORITHM']]

    if algorithm not in allowed_algorithms:
        raise ValueError(
            f"Unexpected algorithm '{algorithm}'. Allowed: {allowed_algorithms}"
        )

    # Choose verification key based on algorithm
    if algorithm in ('RS256', 'RS384', 'RS512'):
        if not app.config['JWKS_URL']:
            raise ValueError("RS256 configured but no JWKS_URL set")
        signing_key = get_jwks_public_key(unverified_header)
    elif algorithm in ('HS256', 'HS384', 'HS512'):
        signing_key = app.config['JWT_SECRET_KEY']
        if not signing_key:
            raise ValueError("JWT_SECRET_KEY not configured")
    else:
        raise ValueError(f"Unsupported algorithm: {algorithm}")

    # FULL verification - signature, expiration, issuer
    claims = jwt.decode(
        token,
        signing_key,
        algorithms=allowed_algorithms,
        options={
            "verify_signature": True,   # ALWAYS verify signature
            "verify_exp": True,          # Check expiration
            "verify_iat": True,          # Check issued-at
            "verify_nbf": True,          # Check not-before
            "require": ["exp", "sub"],   # Require these claims
        },
        issuer=app.config['JWT_ISSUER'] if app.config['JWT_ISSUER'] else None,
    )

    return claims


def extract_token_from_header():
    """Extract Bearer token from Authorization header."""
    auth_header = request.headers.get('Authorization', '')

    if not auth_header:
        return None

    parts = auth_header.split()

    if len(parts) != 2 or parts[0].lower() != 'bearer':
        return None

    return parts[1]


def require_auth(f):
    """Decorator to require valid JWT authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = extract_token_from_header()

        if not token:
            return jsonify({
                'error': 'authorization_required',
                'message': 'Authorization header with Bearer token is required'
            }), 401

        try:
            claims = decode_and_verify_token(token)
        except jwt.ExpiredSignatureError:
            return jsonify({
                'error': 'token_expired',
                'message': 'Token has expired'
            }), 401
        except jwt.InvalidIssuerError:
            return jsonify({
                'error': 'invalid_issuer',
                'message': 'Token issuer is not trusted'
            }), 401
        except jwt.InvalidSignatureError:
            app.logger.warning(
                f"Invalid signature attempt from {request.remote_addr}"
            )
            return jsonify({
                'error': 'invalid_signature',
                'message': 'Token signature verification failed'
            }), 401
        except (jwt.InvalidTokenError, ValueError) as e:
            app.logger.warning(
                f"Invalid token from {request.remote_addr}: {e}"
            )
            return jsonify({
                'error': 'invalid_token',
                'message': 'Token is invalid'
            }), 401

        # Store verified claims in request context
        g.current_user = claims
        g.jwt_token = token

        return f(*args, **kwargs)

    return decorated


def require_role(*required_roles):
    """Decorator to require specific roles in JWT claims."""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            user_roles = g.current_user.get('roles', [])
            if isinstance(user_roles, str):
                user_roles = [user_roles]

            if not any(role in user_roles for role in required_roles):
                return jsonify({
                    'error': 'insufficient_permissions',
                    'message': f'Required roles: {required_roles}'
                }), 403

            return f(*args, **kwargs)
        return decorated
    return decorator


def forward_to_backend(method, path, **kwargs):
    """Forward request to backend service with verified user claims as headers."""
    backend_url = f"{app.config['BACKEND_SERVICE_URL']}{path}"

    # Forward verified claims as trusted internal headers
    headers = {
        'X-Verified-User-Id': str(g.current_user.get('sub', '')),
        'X-Verified-User-Email': g.current_user.get('email', ''),
        'X-Verified-User-Roles': ','.join(
            g.current_user.get('roles', [])
            if isinstance(g.current_user.get('roles', []), list)
            else [g.current_user.get('roles', '')]
        ),
        'X-Request-Id': request.headers.get('X-Request-Id', ''),
        'Content-Type': request.content_type or 'application/json',
    }

    try:
        resp = requests.request(
            method=method,
            url=backend_url,
            headers=headers,
            data=request.get_data(),
            params=request.args,
            timeout=30,
        )
        return (resp.content, resp.status_code, dict(resp.headers))
    except requests.RequestException as e:
        app.logger.error(f"Backend request failed: {e}")
        return jsonify({
            'error': 'service_unavailable',
            'message': 'Backend service is unavailable'
        }), 502


