@app.route('/dev/generate-test-token', methods=['POST'])
def generate_test_token():
    """Generate a test token for development. Disable in production."""
    if os.environ.get('FLASK_ENV') == 'production':
        return jsonify({'error': 'Not available in production'}), 404

    if not app.config['JWT_SECRET_KEY']:
        return jsonify({'error': 'JWT_SECRET_KEY not configured'}), 500

    data = request.get_json() or {}

    now = datetime.utcnow()
    claims = {
        'sub': data.get('user_id', 'test-user-1'),
        'email': data.get('email', 'test@example.com'),
        'roles': data.get('roles', ['user']),
        'iss': app.config['JWT_ISSUER'],
        'iat': now,
        'exp': now + timedelta(hours=1),
    }

    token = jwt.encode(
        claims,
        app.config['JWT_SECRET_KEY'],
        algorithm=app.config['JWT_ALGORITHM']
    )

    return jsonify({
        'token': token,
        'claims': {k: str(v) for k, v in claims.items()},
        'usage': f'Authorization: Bearer {token}'
    })


